//! Cross-language regression tests.
//!
//! Expected values are generated by `python_reference_generator.py` from the
//! Python implementation checked into this repository.  Python is deliberately
//! not invoked by these tests, so downstream Rust builds do not need NumPy,
//! SciPy, or Matplotlib installed.

use gammachirp_rs::gcfb_v211::{
    gammachirp::{self as gc, Carrier, Normalization},
    gcfb_v211::{self as fb211, AcfStatus, ControlMode as Control211, GcParam as Param211},
    utils as utils211,
};
use gammachirp_rs::gcfb_v234::{
    gcfb_v234::{
        self as fb234, ControlMode as Control234, DynHpaf, EmParam, GainReference,
        GcParam as Param234,
    },
    utils::{self as utils234, Floor, ParamTransFunc},
};
use ndarray::{Array2, ArrayView2};
use serde_json::Value;

const REFERENCE_JSON: &str = include_str!("fixtures/python_reference.json");

fn references() -> Value {
    serde_json::from_str(REFERENCE_JSON).expect("the checked-in Python fixture must be valid JSON")
}

fn expected_values(node: &Value) -> Vec<f64> {
    node["values"]
        .as_array()
        .expect("encoded array must contain values")
        .iter()
        .map(|value| value.as_f64().expect("fixture arrays contain numbers"))
        .collect()
}

fn expected_shape(node: &Value) -> Vec<usize> {
    node["shape"]
        .as_array()
        .expect("encoded array must contain a shape")
        .iter()
        .map(|value| value.as_u64().expect("shape entries are integers") as usize)
        .collect()
}

fn assert_values(label: &str, actual: &[f64], expected: &Value, atol: f64, rtol: f64) {
    let expected = expected_values(expected);
    assert_eq!(
        actual.len(),
        expected.len(),
        "{label}: Rust and Python lengths differ"
    );
    for (index, (&rust, &python)) in actual.iter().zip(&expected).enumerate() {
        let tolerance = atol + rtol * python.abs();
        assert!(
            rust.is_finite() && (rust - python).abs() <= tolerance,
            "{label}[{index}]: Rust {rust:.17e}, Python {python:.17e}, \
             difference {:.3e}, tolerance {tolerance:.3e}",
            (rust - python).abs()
        );
    }
}

fn assert_scalar(label: &str, actual: f64, expected: f64, atol: f64, rtol: f64) {
    let tolerance = atol + rtol * expected.abs();
    assert!(
        actual.is_finite() && (actual - expected).abs() <= tolerance,
        "{label}: Rust {actual:.17e}, Python {expected:.17e}, difference {:.3e}, tolerance {tolerance:.3e}",
        (actual - expected).abs()
    );
}

fn flattened(view: ArrayView2<'_, f64>) -> Vec<f64> {
    view.rows()
        .into_iter()
        .flat_map(|row| row.to_vec())
        .collect()
}

fn selected_rows(values: ArrayView2<'_, f64>, bins: &[usize]) -> Vec<f64> {
    let mut selected = Vec::with_capacity(values.nrows() * bins.len());
    for row in values.rows() {
        selected.extend(bins.iter().map(|&bin| row[bin]));
    }
    selected
}

fn v211_param(control: Control211) -> Param211 {
    Param211 {
        fs: 8_000.0,
        num_ch: 4,
        f_range: [200.0, 1_500.0],
        out_mid_crct: "No".into(),
        ctrl: control,
        ..Param211::default()
    }
}

fn v234_param(control: Control234, processing: &str, hearing_loss: &str) -> Param234 {
    Param234 {
        fs: 8_000.0,
        num_ch: 4,
        f_range: [200.0, 1_500.0],
        out_mid_crct: "No".into(),
        ctrl: control,
        dyn_hpaf: DynHpaf {
            str_prc: processing.into(),
            ..DynHpaf::default()
        },
        hloss_type: hearing_loss.into(),
        hloss_compression_health: (hearing_loss == "HL3").then_some(0.5),
        gain_ref: GainReference::NormalizeIoFunction,
        ..Param234::default()
    }
}

fn parity_input() -> Vec<f64> {
    let mut input = vec![0.0; 32];
    input[..6].copy_from_slice(&[1.0, -0.25, 0.5, 0.0, -0.1, 0.2]);
    input
}

#[test]
fn v211_scalar_scales_and_level_calibration_match_python() {
    let fixture = references();
    let scalar = &fixture["v211"]["utility_scalars"];
    let input = [-3.0, -1.0, 2.0, 4.0];
    assert_scalar(
        "rms",
        utils211::rms(&input),
        scalar["rms"].as_f64().unwrap(),
        1e-14,
        1e-14,
    );

    let powers: Vec<u64> = [1, 2, 3, 15, 16, 17, 1000]
        .map(|value| utils211::nextpow2(value) as u64)
        .to_vec();
    let expected_powers: Vec<u64> = scalar["nextpow2"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_u64().unwrap())
        .collect();
    assert_eq!(powers, expected_powers);

    let mel: Vec<f64> = [50.0, 100.0, 1000.0, 6000.0]
        .map(utils211::freq2mel)
        .to_vec();
    assert_values("freq2mel", &mel, &scalar["freq2mel"], 1e-12, 1e-13);
    let frequency: Vec<f64> = [75.0, 500.0, 1000.0, 2500.0]
        .map(utils211::mel2freq)
        .to_vec();
    assert_values("mel2freq", &frequency, &scalar["mel2freq"], 1e-11, 1e-13);

    let erb_fixture = &fixture["v211"]["erb"];
    let (erb, width) = utils211::freq2erb(&[0.0, 50.0, 100.0, 1000.0, 6000.0]);
    assert_values(
        "ERB rate",
        erb.as_slice().unwrap(),
        &erb_fixture["rate"],
        1e-13,
        1e-13,
    );
    assert_values(
        "ERB width",
        width.as_slice().unwrap(),
        &erb_fixture["width"],
        1e-12,
        1e-13,
    );
    let (inverse, inverse_width) = utils211::erb2freq(erb.as_slice().unwrap());
    assert_values(
        "ERB inverse",
        inverse.as_slice().unwrap(),
        &erb_fixture["inverse_frequency"],
        1e-10,
        1e-13,
    );
    assert_values(
        "ERB inverse width",
        inverse_width.as_slice().unwrap(),
        &erb_fixture["inverse_width"],
        1e-11,
        1e-13,
    );

    let equal_fixture = &fixture["v211"]["equal_erb"];
    let (equal_frequency, equal_erb) =
        utils211::equal_freq_scale(utils211::FrequencyScale::Erb, 6, [100.0, 6000.0]).unwrap();
    assert_values(
        "equal ERB frequency",
        equal_frequency.as_slice().unwrap(),
        &equal_fixture["frequency"],
        1e-10,
        1e-13,
    );
    assert_values(
        "equal ERB scale",
        equal_erb.as_slice().unwrap(),
        &equal_fixture["erb"],
        1e-12,
        1e-13,
    );

    let (equalized, levels) = utils211::eqlz2meddis_hc_level(&input, 63.0).unwrap();
    let level_fixture = &fixture["v211"]["level_equalization"];
    assert_values(
        "v211 calibrated signal",
        equalized.as_slice().unwrap(),
        &level_fixture["signal"],
        1e-12,
        1e-13,
    );
    assert_values(
        "v211 calibration metadata",
        &levels,
        &level_fixture["level"],
        1e-12,
        1e-13,
    );
}

#[test]
fn v211_windows_filtering_and_framing_match_python() {
    let fixture = references();
    let windows = &fixture["v211"]["windows"];
    for (key, expected_name) in [
        ("HAM", "Hamming"),
        ("HAN", "Hanning/Cosine"),
        ("BLA", "Blackman"),
        ("LINE", "Line"),
    ] {
        let (window, name) = utils211::taper_window(12, key, Some(4), 3.0).unwrap();
        assert_eq!(name, expected_name);
        assert_eq!(windows[key]["name"].as_str().unwrap(), expected_name);
        assert_values(
            key,
            window.as_slice().unwrap(),
            &windows[key]["values"],
            1e-14,
            1e-13,
        );
    }

    let filtered = utils211::fftfilt(&[0.25, -0.5, 1.5, 0.75], &[1.0, -2.0, 0.5, 3.0, -1.0]);
    assert_values(
        "fftfilt",
        filtered.as_slice().unwrap(),
        &fixture["v211"]["fftfilt"],
        1e-13,
        1e-13,
    );

    let signal: Vec<f64> = (1..10).map(|value| value as f64).collect();
    let (frames, centers) = fb211::set_frame4time_sequence(&signal, 6, Some(3)).unwrap();
    let frame_fixture = &fixture["v211"]["frames"];
    assert_eq!(
        vec![frames.nrows(), frames.ncols()],
        expected_shape(&frame_fixture["values"])
    );
    assert_values(
        "framed signal",
        &flattened(frames.view()),
        &frame_fixture["values"],
        0.0,
        0.0,
    );
    let centers: Vec<f64> = centers.iter().map(|&value| value as f64).collect();
    assert_values(
        "frame centers",
        &centers,
        &frame_fixture["centers"],
        0.0,
        0.0,
    );
}

